    97→// ListRecipes lists all recipes from the registry
    98→func (h *Handler) ListRecipes(c *fiber.Ctx) error {
    99→	ctx := context.Background()
   100→
   101→	// Get query parameters for filtering
   102→	recipeType := c.Query("type", "")
   103→
   104→	var recipes []*UnifiedRecipeMetadata
   105→	var err error
   106→
