   108→	if h.recipeRegistry == nil {
   109→		return c.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
   110→			"error": "RecipeRegistry not available - check SeaweedFS connectivity",
   111→		})
   112→	}
   113→
   114→	if recipeType != "" {
   115→		recipes, err = h.recipeRegistry.QueryByType(ctx, recipeType)
   116→	} else {
   117→		recipes, err = h.recipeRegistry.ListAllRecipes(ctx)
   118→	}
   119→
   120→	if err != nil {
   121→		return c.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
   122→			"error":   "Failed to list recipes",
   123→			"details": err.Error(),
   124→		})
   125→	}
   126→
   127→	// Transform to response format
   128→	response := make([]map[string]interface{}, 0, len(recipes))
   129→	for _, recipe := range recipes {
   130→		item := map[string]interface{}{
   131→			"id":         recipe.Metadata.ID,
   132→			"name":       recipe.Metadata.Name,
   133→			"version":    recipe.Metadata.Version,
   134→			"type":       recipe.Metadata.Type,
