   313→// SearchRecipes searches for recipes by keyword
   314→func (h *Handler) SearchRecipes(c *fiber.Ctx) error {
   315→	query := c.Query("q")
   316→	if query == "" {
   317→		return c.Status(fiber.StatusBadRequest).JSON(fiber.Map{
   318→			"error": "Search query is required",
   319→		})
   320→	}
   321→
   322→	if h.recipeRegistry == nil {
   323→		return c.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
   324→			"error": "Recipe registry not available",
   325→		})
   326→	}
   327→
   328→	ctx := context.Background()
   329→
   330→	// Get all recipes and filter by query
   331→	recipes, err := h.recipeRegistry.ListAllRecipes(ctx)
   332→	if err != nil {
   333→		return c.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
   334→			"error":   "Failed to search recipes",
   335→			"details": err.Error(),
   336→		})
   337→	}
   338→
   339→	// Filter recipes by search query
   340→	query = strings.ToLower(query)
   341→	var matches []*UnifiedRecipeMetadata
   342→
   343→	for _, recipe := range recipes {
   344→		if strings.Contains(strings.ToLower(recipe.Metadata.ID), query) ||
   345→			strings.Contains(strings.ToLower(recipe.Metadata.Name), query) ||
   346→			containsInTags(recipe.Metadata.Tags, query) ||
   347→			containsInTags(recipe.Metadata.Categories, query) {
   348→			matches = append(matches, recipe)
   349→		}
   350→	}
   351→
   352→	return c.JSON(fiber.Map{
   353→		"query":   query,
   354→		"count":   len(matches),
   355→		"recipes": matches,
   356→	})
   357→}
